func TestCacheKeySortsParams(t *testing.T) {
	c := &Client{}

	got := c.cacheKey("/1.0/search/artists", map[string]string{
		"artistName": "Radiohead",
		"p":          "2",
	})

	h := sha256.Sum256([]byte("/1.0/search/artistsartistName=Radioheadp=2"))
	want := hex.EncodeToString(h[:8])
	if got != want {
		t.Fatalf("cacheKey = %q, want sorted-parameter key %q", got, want)
	}

	gotReordered := c.cacheKey("/1.0/search/artists", map[string]string{
		"p":          "2",
		"artistName": "Radiohead",
	})
	if gotReordered != got {
		t.Fatalf("cacheKey differs for reordered params: %q != %q", gotReordered, got)
	}
}
